type ESFile = {
  path: string
  outpath: string
  text: string
}

type Token = {
  type: TokenType
  value: string
  start: number
  end: number
}

type spawnSyncOptions = {
  cmd: string[]
  cwd?: string
  runtime?: true | string[]
  stdio?: child_process.StdioOptions
  timeout?: number
  killSignal?: number | Signals | undefined
}

